import re
import json

# ---------- STEP 1: Fix JSON ----------
def fix_json(input_text):
    return re.sub(r'([^{,]+):', lambda m: f'"{m.group(1).strip()}":', input_text)


# ---------- STEP 2: Normalize text ----------
def normalize(text):
    text = text.lower()
    text = re.sub(r'[^a-z0-9 ]', ' ', text)   # remove symbols
    text = re.sub(r'\s+', ' ', text)          # remove extra spaces
    return text.strip()


# ---------- STEP 3: Classification ----------
def classify(data):
    result = {
        "haircut": 0,
        "trim": 0,
        "haircut_and_trim": 0,   # 🔥 NEW FIELD
        "kids haircut": 0,
        "basic detan": 0,
        "detan": 0,
        "scrub": 0,
        "charcoal scrub": 0,
        "facial": 0,
        "golden facial": 0,
        "radial facial": 0,
        "golden mask": 0,
        "charcoal facial": 0,
        "hair spa": 0,
        "others": 0
    }

    for key, value in data.items():
        text = normalize(key)
        matched = False

        # ---- Detect core services first ----
        has_haircut = any(word in text for word in [
            "haircut", "hair cut", "cut", "cuting", "haricut", "harcut"
        ])

        has_trim = any(word in text for word in [
            "trim", "tirm", "trm"
        ])

        # ---- Haircut & Trim combo ----
        if has_haircut and has_trim:
            result["haircut_and_trim"] += value

        # ---- Individual counts ----
        if has_haircut:
            result["haircut"] += value
            matched = True

        if has_trim:
            result["trim"] += value
            matched = True

        # ---- Kids ----
        if "kid" in text:
            result["kids haircut"] += value
            matched = True

        # ---- Basic Detan ----
        if "basic detan" in text:
            result["basic detan"] += value
            matched = True

        # ---- Detan ----
        if any(word in text for word in ["detan", "de tan", "tan"]):
            result["detan"] += value
            matched = True

        # ---- Scrub ----
        if "scrub" in text:
            result["scrub"] += value
            matched = True

        # ---- Charcoal ----
        if "charcoal" in text:
            result["charcoal scrub"] += value
            matched = True

        # ---- Facial ----
        if any(word in text for word in ["facial", "face", "faceyal"]):
            result["facial"] += value
            matched = True

        # ---- Golden ----
        if "gold" in text:
            result["golden facial"] += value
            matched = True

        # ---- Radial ----
        if any(word in text for word in ["radial", "radian"]):
            result["radial facial"] += value
            matched = True

        # ---- Mask ----
        if "mask" in text:
            result["golden mask"] += value
            matched = True

        # ---- Hair Spa ----
        if "spa" in text:
            result["hair spa"] += value
            matched = True

        # ---- Others ----
        if not matched:
            result["others"] += value

    return result




